struct FrameReader16 {
    child: Child,
    frame_index: u64,
    width: usize,
    height: usize,
    read_buf: Vec<u8>,
    done: bool,
}
impl FrameReader16 {
    fn new(child: Child, width: usize, height: usize) -> Self {
        Self {
            child,
            frame_index: 0,
            width,
            height,
            read_buf: vec![0u8; width * height * 6],
            done: false,
        }
    }
}
